//! Timing harness for mesh depth fusion and monocular cue stack.
//!
//! ```text
//! cargo run -p distributed-inference --release --bin bench-mesh-depth
//! cargo run -p distributed-inference --release --bin bench-mesh-depth -- --w 720 --h 720 --iters 20
//! ```

use std::time::Instant;

use distributed_inference::depth_extrusion::estimate_depth_classical_normalized;
use distributed_inference::depth_monocular_cues::build_monocular_cue_maps;
use distributed_inference::mesh_depth_field::{build_mesh_depth_field, MeshDepthConfig};
fn arg_usize(flag: &str, default: usize) -> usize {
    let mut args = std::env::args().skip(1);
    while let Some(arg) = args.next() {
        if arg == flag {
            return args
                .next()
                .and_then(|value| value.parse::<usize>().ok())
                .unwrap_or(default);
        }
    }
    default
}

fn deterministic_rgb(seed: usize, pixels: usize) -> Vec<f32> {
    let mut v = Vec::with_capacity(pixels * 3);
    for i in 0..pixels {
        let t = (i ^ seed).wrapping_mul(0x9e37_79b9);
        let a = ((((t >> 8) ^ (t >> 24)) % 101) as f32 / 100.0).clamp(0.0, 1.0);
        let b = ((((t >> 16) ^ t) % 101) as f32 / 100.0).clamp(0.0, 1.0);
        let c = ((((t.rotate_left(13)) >> 8) % 101) as f32 / 100.0).clamp(0.0, 1.0);
        v.push(a);
        v.push(b);
        v.push(c);
    }
    v
}

fn bench(name: &str, iters: usize, mut f: impl FnMut()) {
    f(); // warm one
    let t0 = Instant::now();
    for _ in 0..iters {
        f();
    }
    let elapsed = t0.elapsed();
    let per = elapsed / iters as u32;
    println!(
        "{name}: {iters} iters → total {:?} (~{:?} per call)",
        elapsed, per
    );
}

fn main() {
    let w = arg_usize("--w", 512);
    let h = arg_usize("--h", 512);
    let iters = arg_usize("--iters", 16);
    if w == 0 || h == 0 {
        eprintln!("--w/--h must be positive");
        std::process::exit(2);
    }
    let pixels = w * h;
    let rgb = deterministic_rgb(0x6d65_7368usize, pixels);

    println!(
        "bench-mesh-depth: {}×{} (~{:.2} Mp), {} iters, release binary recommended",
        w,
        h,
        pixels as f64 / 1e6,
        iters
    );

    bench("classical_normalized", iters, || {
        let _ = estimate_depth_classical_normalized(&rgb, w, h).expect("classical depth");
    });

    bench("monocular_cue_maps", iters, || {
        build_monocular_cue_maps(&rgb, w, h).expect("mono cues");
    });

    bench("mesh_depth_default (mono off)", iters, || {
        let _ = build_mesh_depth_field(
            &rgb,
            w as u32,
            h as u32,
            &MeshDepthConfig::default(),
            None,
            None,
        )
        .expect("mesh");
    });

    let mut cfg_mono = MeshDepthConfig::default();
    cfg_mono.monocular_cue_blend = 0.25_f32;

    bench("mesh_depth_mono_blend", iters, || {
        let _ = build_mesh_depth_field(&rgb, w as u32, h as u32, &cfg_mono, None, None)
            .expect("mesh+mono");
    });
}
